1	import crypto from 'node:crypto';
2	
3	export function verifySharedSecret(expectedSecret: string | undefined, providedSecret: string | undefined): boolean {
4	    if (!expectedSecret) return false;
5	
6	    const expected = Buffer.from(expectedSecret);
7	    const provided = Buffer.from(providedSecret ?? '');
8	
9	    if (expected.length === 0 || expected.length !== provided.length) {
10	        return false;
11	    }
12	
13	    return crypto.timingSafeEqual(expected, provided);
14	}
15	
16	export function verifyStripeSignature(
17	    rawBody: string,
18	    signatureHeader: string | undefined,
19	    signingSecret: string | undefined,
20	    toleranceSeconds = 300,
21	    nowSeconds = Math.floor(Date.now() / 1000),
22	): boolean {
23	    if (!signatureHeader || !signingSecret) return false;
24	
25	    let timestamp: number | null = null;
26	    const v1Candidates: string[] = [];
27	
28	    for (const part of signatureHeader.split(',')) {
29	        const [key, value] = part.trim().split('=', 2);
30	        if (!key || !value) continue;
31	
32	        if (key === 't') {
33	            const parsed = Number(value);
34	            timestamp = Number.isFinite(parsed) ? parsed : null;
35	        }
36	
37	        if (key === 'v1') {
38	            v1Candidates.push(value.toLowerCase());
39	        }
40	    }
41	
42	    if (timestamp === null || v1Candidates.length === 0) {
43	        return false;
44	    }
45	
46	    const ageSeconds = Math.abs(nowSeconds - timestamp);
47	    if (ageSeconds > Math.max(1, toleranceSeconds)) {
48	        return false;
49	    }
50	
51	    const signedPayload = `${timestamp}.${rawBody}`;
52	    const expectedSignature = crypto
53	        .createHmac('sha256', signingSecret)
