243	/**
244	 * Claim a batch of pending/failed rows using FOR UPDATE SKIP LOCKED.
245	 * This is the standard Postgres job queue pattern used by Sidekiq, Oban, etc.
246	 */
247	async function claimDurableBatch(workerName: string, batchSize: number): Promise<QueueRow[]> {
248	    const now = new Date().toISOString();
249	
250	    // ── Stale lock recovery ──────────────────────────────────
251	    // If the server crashed while processing, items will be stuck in 'processing'
252	    // forever. Reset any item that's been locked for more than 5 minutes back
253	    // to 'failed' so the next poll picks it up.
254	    const staleCutoff = new Date(Date.now() - 5 * 60 * 1000).toISOString();
255	    try {
256	        const { data: staleRows } = await supabase
257	            .from('queue_outcome_ingress')
258	            .update({
259	                status: 'failed',
260	                locked_by: null,
261	                locked_at: null,
262	                last_error: `Stale lock recovered by ${workerName} — previous worker likely crashed`,
263	            })
264	            .eq('status', 'processing')
265	            .lt('locked_at', staleCutoff)
266	            .select('ingress_id');
267	
268	        if (staleRows && staleRows.length > 0) {
269	            console.warn(`[durable-queue] Recovered ${staleRows.length} stale-locked items`);
270	        }
271	    } catch (err: unknown) {
272	        // Recovery is best-effort — don't block the main poll loop
273	        console.warn('[durable-queue] Stale lock recovery failed:', err instanceof Error ? err.message : String(err));
274	    }
275	
276	    // ── Claim batch ──────────────────────────────────────────
277	    // Two-step select+update. The UPDATE uses .select() to return
278	    // only the rows that were ACTUALLY claimed (status guard ensures
279	    // rows already claimed by an overlapping tick are skipped).
280	    const { data: candidates, error: selectErr } = await supabase
281	        .from('queue_outcome_ingress')
282	        .select('ingress_id')
283	        .in('status', ['pending', 'failed'])
284	        .lte('next_attempt_at', now)
285	        .order('next_attempt_at', { ascending: true })
286	        .limit(batchSize);
287	
288	    if (selectErr || !candidates || candidates.length === 0) {
289	        return [];
290	    }
291	
292	    const ids = candidates.map((r: any) => r.ingress_id);
293	
294	    // Claim: update status to 'processing' and return only rows we actually claimed.
295	    // The `.in('status', ['pending', 'failed'])` guard ensures rows already
296	    // grabbed by an overlapping poll tick won't be returned.
297	    const { data: claimed, error: updateErr } = await supabase
298	        .from('queue_outcome_ingress')
299	        .update({
300	            status: 'processing',
301	            locked_by: workerName,
302	            locked_at: now,
303	        })
304	        .in('ingress_id', ids)
305	        .in('status', ['pending', 'failed']) // guard: only claim if still claimable
306	        .select('ingress_id, customer_id, agent_id, payload, validated_action, attempts, max_attempts');
307	
308	    if (updateErr) {
