390	    const payload = row.payload as Record<string, unknown>;
391	
392	    // Build the NormalizedOutcomeRow from the stored payload.
393	    // The payload is the full parsed SDK body — extract every field
394	    // that ingestOutcome() can consume to maintain parity with sync path.
395	    const verifierSignal = typeof payload.verifier_signal === 'object' && payload.verifier_signal !== null
396	        ? payload.verifier_signal as Record<string, unknown>
397	        : null;
398	
399	    const normalizedRow: NormalizedOutcomeRow = {
400	        agent_id: row.agent_id,
401	        action_name: (payload.action_name as string) ?? 'unknown_action',
402	        issue_type: (payload.issue_type as string) ?? 'unknown',
403	        success: payload.success === true,
404	        outcome_score: typeof payload.outcome_score === 'number' ? payload.outcome_score : undefined,
405	        business_outcome: (payload.business_outcome as string) ?? undefined,
406	        session_id: (payload.session_id as string) ?? undefined,
407	        response_time_ms: typeof payload.response_time_ms === 'number' ? payload.response_time_ms : undefined,
408	        feedback_signal: (payload.feedback_signal as string) ?? undefined,
409	        decision_id: (payload.decision_id as string) ?? undefined,
410	        episode_id: (payload.episode_id as string) ?? undefined,
411	        task_name: (payload.task_name as string) ?? undefined,
412	        raw_context: typeof payload.raw_context === 'object' && payload.raw_context !== null
413	            ? payload.raw_context as Record<string, unknown>
414	            : undefined,
415	        error_code: (payload.error_code as string) ?? undefined,
416	        error_message: (payload.error_message as string) ?? undefined,
417	        idempotency_key: (payload.idempotency_key as string) ?? undefined,
418	        environment: (payload.environment as string) ?? undefined,
419	        customer_tier: (payload.customer_tier as string) ?? undefined,
420	        // Verifier signal — SDK sends as nested { source, value }
421	        verifier_source: (verifierSignal?.source as string) ?? undefined,
422	        verifier_value: verifierSignal?.value as string | number | boolean | undefined ?? undefined,
423	        // Task mapping metadata (parser-provided)
