383	                    opened_confidence_source_reason:
384	                        data.previous_cycle.opened_confidence_source_reason ?? null,
385	                }
386	                : null,
387	        };
388	    } catch (err: any) {
389	        console.warn(
390	            '[cohort-cycle] RPC threw; using in-memory fallback:',
391	            err?.message ?? 'unknown error',
392	        );
393	        return fallbackUpsertRecommendationCohortCycle(observation);
394	    }
395	}
