        if (res.status !== 401) {
            console.error(`  -> FAILED: Expected 401, got ${res.status}`);
            allPassed = false;
        } else {
            console.log('  -> PASSED');
        }
    } catch (e) {
        console.error('  -> Error POST admin/actions:', e.message);
        allPassed = false;
